#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

kernel void 
lud_diagonal(float *m, local float *shadow, int matrix_dim, int offset)
{
  int i, j;
  int array_offset = offset*matrix_dim+offset;

  for(i=0; i < BLOCK_SIZE; i++){
    shadow[i*BLOCK_SIZE+get_local_id(0)] = m[array_offset+get_local_id(0)];
    array_offset += matrix_dim;
  }
  barrier(CLK_LOCAL_MEM_FENCE);

  for(i=0; i < BLOCK_SIZE-1; i++) {
    if (get_local_id(0) > i){
      for(j=0; j < i; j++)
        shadow[i*BLOCK_SIZE+get_local_id(0)] -= shadow[j*BLOCK_SIZE+get_local_id(0)] * shadow[i*BLOCK_SIZE+j];
      shadow[i*BLOCK_SIZE+get_local_id(0)] /= shadow[i*BLOCK_SIZE+i];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (get_local_id(0) > i){
      for(j=0; j < i+1; j++)
        shadow[(i+1)*BLOCK_SIZE+get_local_id(0)] -= shadow[(i+1)*BLOCK_SIZE+j] * shadow[j*BLOCK_SIZE+get_local_id(0)];
    }
    barrier(CLK_LOCAL_MEM_FENCE);
  }

  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; i < BLOCK_SIZE; i++){
    m[array_offset+get_local_id(0)] = shadow[i*BLOCK_SIZE+get_local_id(0)];
    array_offset += matrix_dim;
  }
}

kernel void
lud_perimeter(float *m, local float *dia, local float *peri_row, local float *peri_col, int matrix_dim, int offset)
{
  int i, j, array_offset;
  int idx;

  if (get_local_id(0) < BLOCK_SIZE) {
    idx = get_local_id(0);

    array_offset = offset*matrix_dim+offset;
    for (i=0; i < BLOCK_SIZE/2; i++){
      dia[i*BLOCK_SIZE+idx] = m[array_offset+idx];
      array_offset += matrix_dim;
    }

    array_offset = offset*matrix_dim+offset;
    for (i=0; i < BLOCK_SIZE; i++) {
      peri_row[i*BLOCK_SIZE+idx] = m[array_offset+(get_group_id(0)+1)*BLOCK_SIZE+idx];
      array_offset += matrix_dim;
    }
  } else {
    idx = get_local_id(0) - BLOCK_SIZE;

    array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
    for (i=BLOCK_SIZE/2; i < BLOCK_SIZE; i++){
      dia[i*BLOCK_SIZE+idx] = m[array_offset+idx];
      array_offset += matrix_dim;
    }

    array_offset = (offset+(get_group_id(0)+1)*BLOCK_SIZE)*matrix_dim+offset;
    for (i=0; i < BLOCK_SIZE; i++) {
      peri_col[idx*BLOCK_SIZE+i] = m[array_offset+idx];
      array_offset += matrix_dim;
    }
  }
  barrier(CLK_LOCAL_MEM_FENCE);

  if (get_local_id(0) < BLOCK_SIZE) { 
    idx = get_local_id(0);
    for(i=1; i < BLOCK_SIZE; i++){
      for (j=0; j < i; j++)
        peri_row[i*BLOCK_SIZE+idx] -= dia[i*BLOCK_SIZE+j] * peri_row[j*BLOCK_SIZE+idx];
    }
  } else { 
    idx = get_local_id(0) - BLOCK_SIZE;
    for(i=0; i < BLOCK_SIZE; i++){
      for(j=0; j < i; j++)
        peri_col[idx*BLOCK_SIZE+i] -= peri_col[idx*BLOCK_SIZE+j] * dia[j*BLOCK_SIZE+i];
      peri_col[idx*BLOCK_SIZE+i] /= dia[i*BLOCK_SIZE+i];
    }
  }

  barrier(CLK_LOCAL_MEM_FENCE);

  if (get_local_id(0) < BLOCK_SIZE) { 
    idx = get_local_id(0);
    array_offset = (offset+1)*matrix_dim+offset;
    for(i=1; i < BLOCK_SIZE; i++){
      m[array_offset+(get_group_id(0)+1)*BLOCK_SIZE+idx] = peri_row[i*BLOCK_SIZE+idx];
      array_offset += matrix_dim;
    }
  } else { 
    idx = get_local_id(0) - BLOCK_SIZE;
    array_offset = (offset+(get_group_id(0)+1)*BLOCK_SIZE)*matrix_dim+offset;
    for(i=0; i < BLOCK_SIZE; i++){
      m[array_offset+idx] = peri_col[i*BLOCK_SIZE+idx];
      array_offset += matrix_dim;
    }
  }
}

kernel void
lud_internal(float *m, local float *peri_row, local float *peri_col, int matrix_dim, int offset)
{
  int i;
  float sum;

  int global_row_id = offset + (get_group_id(1)+1)*BLOCK_SIZE;
  int global_col_id = offset + (get_group_id(0)+1)*BLOCK_SIZE;

  peri_row[get_local_id(1)*BLOCK_SIZE+get_local_id(0)] = m[(offset+get_local_id(1))*matrix_dim+global_col_id+get_local_id(0)];
  peri_col[get_local_id(1)*BLOCK_SIZE+get_local_id(0)] = m[(global_row_id+get_local_id(1))*matrix_dim+offset+get_local_id(0)];

  barrier(CLK_LOCAL_MEM_FENCE);

  sum = 0;
  for (i=0; i < BLOCK_SIZE; i++)
    sum += peri_col[get_local_id(1)*BLOCK_SIZE+i] * peri_row[i*BLOCK_SIZE+get_local_id(0)];
  m[(global_row_id+get_local_id(1))*matrix_dim+global_col_id+get_local_id(0)] -= sum;
}
